'use client'

import Link from 'next/link'
import { usePathname } from 'next/navigation'

const P = '#03254c', S = '#c4e8ff'

// Main nav items (left group)
const MAIN_ITEMS = [
  { href: '/',            label: 'Home',        icon: '🏠' },
  { href: '/statistics',  label: 'Statistics',  icon: '📊' },
  { href: '/watch-party', label: 'Watch Party', icon: '🍿' },
  { href: '/gallery',     label: 'Gallery',     icon: '📸' },
  { href: '/history',     label: 'History',     icon: '📖' },
  { href: '/games',       label: 'Games',       icon: '🎮' },
  { href: '/locations',   label: 'Locations',   icon: '🗺️' },
]

// Settings separate (right)
const SETTINGS_ITEM = { href: '/settings', label: 'Settings', icon: '⚙️' }

// All items for mobile
const ALL_ITEMS = [...MAIN_ITEMS, SETTINGS_ITEM]

export default function Navbar() {
  const pathname = usePathname()

  const NavLink = ({ href, label, icon, compact = false }: { href: string; label: string; icon: string; compact?: boolean }) => {
    const isActive = pathname === href
    return (
      <Link href={href} style={{
        display: 'flex', alignItems: 'center', gap: compact ? 4 : 6,
        padding: compact ? '7px 10px' : '7px 13px',
        borderRadius: 10, textDecoration: 'none',
        fontWeight: 700, fontSize: compact ? '0.8em' : '0.85em',
        whiteSpace: 'nowrap',
        transition: 'all 0.2s ease',
        background: isActive ? 'white' : 'transparent',
        color: isActive ? P : 'rgba(255,255,255,0.75)',
        boxShadow: isActive ? '0 2px 8px rgba(3,37,76,0.15)' : 'none',
      }}>
        <span style={{ fontSize: '1em' }}>{icon}</span>
        <span>{label}</span>
      </Link>
    )
  }

  return (
    <>
      {/* ── DESKTOP TOP NAVBAR ── */}
      <header style={{
        position: 'sticky', top: 0, zIndex: 40,
        background: P,
        boxShadow: '0 4px 24px rgba(3,37,76,0.25)',
        padding: '0 20px',
        display: 'none',
      }} className="nav-desktop">
        <div style={{
          maxWidth: 1200, margin: '0 auto', height: 62,
          display: 'flex', alignItems: 'center',
          justifyContent: 'space-between', gap: 12,
        }}>
          {/* Logo */}
          <Link href="/" style={{ textDecoration: 'none', display: 'flex', alignItems: 'center', gap: 8, flexShrink: 0 }}>
            <div style={{
              width: 32, height: 32, borderRadius: 9,
              background: 'rgba(196,232,255,0.15)',
              border: '1.5px solid rgba(196,232,255,0.3)',
              display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1em',
            }}>💕</div>
            <span style={{ fontWeight: 900, fontSize: '1.15em', color: 'white', letterSpacing: -0.5 }}>TripLove</span>
          </Link>

          {/* Main nav — left group */}
          <nav style={{
            display: 'flex', gap: 1, flex: 1,
            background: 'rgba(255,255,255,0.07)',
            borderRadius: 12, padding: 4,
            border: '1px solid rgba(196,232,255,0.12)',
            overflow: 'hidden',
          }}>
            {MAIN_ITEMS.map(item => (
              <NavLink key={item.href} {...item} compact />
            ))}
          </nav>

          {/* Settings — right, standalone */}
          <div style={{ flexShrink: 0 }}>
            <NavLink {...SETTINGS_ITEM} />
          </div>
        </div>

        {/* bottom accent line */}
        <div style={{ height: 2, background: `linear-gradient(90deg, transparent, ${S}, transparent)`, opacity: 0.35 }} />
      </header>

      {/* ── MOBILE TOP BAR ── */}
      <header style={{
        position: 'sticky', top: 0, zIndex: 40,
        background: P,
        boxShadow: '0 2px 12px rgba(3,37,76,0.2)',
        padding: '0 20px',
        display: 'none',
      }} className="nav-mobile-top">
        <div style={{ height: 54, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <Link href="/" style={{ textDecoration: 'none', display: 'flex', alignItems: 'center', gap: 8 }}>
            <span style={{ fontSize: '1em' }}>💕</span>
            <span style={{ fontWeight: 900, fontSize: '1.1em', color: 'white', letterSpacing: -0.5 }}>TripLove</span>
          </Link>
        </div>
      </header>

      {/* ── MOBILE BOTTOM NAVBAR ── */}
      <nav style={{
        position: 'fixed', bottom: 0, left: 0, right: 0, zIndex: 40,
        background: P,
        boxShadow: '0 -4px 20px rgba(3,37,76,0.2)',
        padding: '6px 4px calc(6px + env(safe-area-inset-bottom))',
        display: 'none',
      }} className="nav-mobile-bottom">
        <div style={{ display: 'flex', justifyContent: 'space-around', alignItems: 'center', width: '100%' }}>
          {ALL_ITEMS.map(({ href, label, icon }) => {
            const isActive = pathname === href
            return (
              <Link key={href} href={href} style={{
                display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 2,
                padding: '4px 2px', borderRadius: 10,
                textDecoration: 'none', flex: 1,
                transition: 'all 0.2s',
                minWidth: 0, position: 'relative',
              }}>
                {/* active indicator */}
                {isActive && (
                  <div style={{
                    position: 'absolute', top: -6, left: '50%', transform: 'translateX(-50%)',
                    width: 20, height: 2, borderRadius: 1, background: S,
                  }} />
                )}
                <span style={{
                  fontSize: '1.2em', lineHeight: 1,
                  filter: isActive ? 'none' : 'grayscale(0.3)',
                  opacity: isActive ? 1 : 0.6,
                  transition: 'all 0.2s',
                }}>{icon}</span>
                <span className="nav-label" style={{
                  fontSize: '0.52em', fontWeight: 700,
                  color: isActive ? 'white' : 'rgba(255,255,255,0.45)',
                  letterSpacing: 0.1, whiteSpace: 'nowrap',
                  overflow: 'hidden', textOverflow: 'ellipsis',
                  maxWidth: '100%', textAlign: 'center',
                  transition: 'color 0.2s',
                }}>{label}</span>
              </Link>
            )
          })}
        </div>
      </nav>

      {/* Responsive CSS */}
      <style dangerouslySetInnerHTML={{__html: `
        .nav-desktop { display: block !important; }
        .nav-mobile-top { display: none !important; }
        .nav-mobile-bottom { display: none !important; }

        @media (max-width: 768px) {
          .nav-desktop { display: none !important; }
          .nav-mobile-top { display: block !important; }
          .nav-mobile-bottom { display: flex !important; }
        }
        @media (max-width: 360px) {
          .nav-label { display: none !important; }
        }
      `}} />
    </>
  )
}